// VodeoMutation represents an operation that mutates the Vodeo nodes in the graph.
type VodeoMutation struct {
	config
	op            Op
	typ           string
	id            *int
	clearedFields map[string]struct{}
	done          bool
	oldValue      func(context.Context) (*Vodeo, error)
	predicates    []predicate.Vodeo
}

var _ ent.Mutation = (*VodeoMutation)(nil)

// vodeoOption allows management of the mutation configuration using functional options.
type vodeoOption func(*VodeoMutation)

// newVodeoMutation creates new mutation for the Vodeo entity.
func newVodeoMutation(c config, op Op, opts ...vodeoOption) *VodeoMutation {
	m := &VodeoMutation{
		config:        c,
		op:            op,
		typ:           TypeVodeo,
		clearedFields: make(map[string]struct{}),
	}
	for _, opt := range opts {
		opt(m)
	}
	return m
}

// withVodeoID sets the ID field of the mutation.
func withVodeoID(id int) vodeoOption {
	return func(m *VodeoMutation) {
		var (
			err   error
			once  sync.Once
			value *Vodeo
		)
		m.oldValue = func(ctx context.Context) (*Vodeo, error) {
			once.Do(func() {
				if m.done {
					err = errors.New("querying old values post mutation is not allowed")
				} else {
					value, err = m.Client().Vodeo.Get(ctx, id)
				}
			})
			return value, err
		}
		m.id = &id
	}
}

// withVodeo sets the old Vodeo of the mutation.
func withVodeo(node *Vodeo) vodeoOption {
	return func(m *VodeoMutation) {
		m.oldValue = func(context.Context) (*Vodeo, error) {
			return node, nil
		}
		m.id = &node.ID
	}
}

// Client returns a new `ent.Client` from the mutation. If the mutation was
// executed in a transaction (ent.Tx), a transactional client is returned.
func (m VodeoMutation) Client() *Client {
	client := &Client{config: m.config}
	client.init()
	return client
}

// Tx returns an `ent.Tx` for mutations that were executed in transactions;
// it returns an error otherwise.
func (m VodeoMutation) Tx() (*Tx, error) {
	if _, ok := m.driver.(*txDriver); !ok {
		return nil, errors.New("ent: mutation is not running in a transaction")
	}
	tx := &Tx{config: m.config}
	tx.init()
	return tx, nil
}

// ID returns the ID value in the mutation. Note that the ID is only available
// if it was provided to the builder or after it was returned from the database.
func (m *VodeoMutation) ID() (id int, exists bool) {
	if m.id == nil {
		return
	}
	return *m.id, true
}

// IDs queries the database and returns the entity ids that match the mutation's predicate.
// That means, if the mutation is applied within a transaction with an isolation level such
// as sql.LevelSerializable, the returned ids match the ids of the rows that will be updated
// or updated by the mutation.
func (m *VodeoMutation) IDs(ctx context.Context) ([]int, error) {
	switch {
	case m.op.Is(OpUpdateOne | OpDeleteOne):
		id, exists := m.ID()
		if exists {
			return []int{id}, nil
		}
		fallthrough
	case m.op.Is(OpUpdate | OpDelete):
		return m.Client().Vodeo.Query().Where(m.predicates...).IDs(ctx)
	default:
		return nil, fmt.Errorf("IDs is not allowed on %s operations", m.op)
	}
}

// Where appends a list predicates to the VodeoMutation builder.
func (m *VodeoMutation) Where(ps ...predicate.Vodeo) {
	m.predicates = append(m.predicates, ps...)
}

