// users can use type-assertion to append predicates that do not depend on any generated package.
func (m *VodeoMutation) WhereP(ps ...func(*sql.Selector)) {
	p := make([]predicate.Vodeo, len(ps))
	for i := range ps {
		p[i] = ps[i]
	}
	m.Where(p...)
}

